public static BigDecimal parseBigDecimal(String numStr) throws NumberFormatException
{
    String trimmed = numStr.trim();
    if (trimmed.isEmpty()) {
        throw new NumberFormatException("empty String");
    }
    return new BigDecimal(trimmed);
}

public static BigDecimal parseBigDecimal(char[] buffer, int offset, int len)
        throws NumberFormatException
{
    if (len == 0) {
        throw new NumberFormatException("empty String");
    }
    // Trim leading and trailing whitespace
    int start = offset;
    int end = offset + len;
    while (start < end && Character.isWhitespace(buffer[start])) {
        start++;
    }
    while (end > start && Character.isWhitespace(buffer[end - 1])) {
        end--;
    }
    int newLen = end - start;
    if (newLen == 0) {
        throw new NumberFormatException("empty String");
    }
    return new BigDecimal(buffer, start, newLen);
}

public BigDecimal contentsAsDecimal()
    throws NumberFormatException
{
    // Already got a pre-cut array?
    if (_resultArray != null) {
        return NumberInput.parseBigDecimal(_resultArray);
    }
    // Or a shared buffer?
    if (_inputStart >= 0) {
        return NumberInput.parseBigDecimal(_inputBuffer, _inputStart, _inputLen);
    }
    // Or if not, just a single buffer (the usual case)
    if (_segmentSize == 0) {
        return NumberInput.parseBigDecimal(_currentSegment, 0, _currentSize);
    }
    // If not, let's just get it aggregated...
    return NumberInput.parseBigDecimal(contentsAsArray());
}

