public void testBigDecimalWithWhitespace() throws Exception {
    String json = "  123.456  ";
    try {
        BigDecimal result = NumberInput.parseBigDecimal(json);
        assertEquals(new BigDecimal("123.456"), result);
    } catch (NumberFormatException e) {
        fail("Should handle whitespace in BigDecimal parsing");
    }
}

public void testBigDecimalWithEmptyString() throws Exception {
    String json = "   ";
    try {
        NumberInput.parseBigDecimal(json);
        fail("Should throw NumberFormatException for empty/whitespace-only string");
    } catch (NumberFormatException e) {
        // Expected
    }
}

public void testBigDecimalWithCharArray() throws Exception {
    char[] buffer = "  -987.654  ".toCharArray();
    try {
        BigDecimal result = NumberInput.parseBigDecimal(buffer, 0, buffer.length);
        assertEquals(new BigDecimal("-987.654"), result);
    } catch (NumberFormatException e) {
        fail("Should handle whitespace in char array BigDecimal parsing");
    }
}
